DROP FUNCTION IF EXISTS feguslocal.obtener_bienesrealizables_lista(p_id_cliente integer, p_id_load_local bigint) CASCADE;
CREATE OR REPLACE FUNCTION feguslocal.obtener_bienesrealizables_lista(p_id_cliente integer, p_id_load_local bigint)  RETURNS SETOF feguslocal.bienesrealizables  LANGUAGE plpgsql AS $function$ BEGIN     RETURN QUERY SELECT * FROM feguslocal.bienesrealizables t     WHERE t.id_cliente = p_id_cliente AND t.id_load_local = p_id_load_local; END; $function$ 
